impl Args {
    pub fn parse() -> Result<Self, String> {
        let args: Vec<String> = env::args().collect();
        if args.len() < 2 {
            return Err("Usage: rustcli <command> [flags...]".to_string());
        }
        let command = args[1].clone();
        let flags = args[2..].to_vec();
        Ok(Args { command, flags })
    }
}

